import json

business_attributes = locals()['var_function-call-4754483256876976487']

qualified_businesses = set()

for business in business_attributes:
    attributes = business.get('attributes')
    business_id = business.get('business_id')

    if not attributes:
        continue

    has_bike_parking = False
    if 'BikeParking' in attributes:
        try:
            # Python evaluates 'True' as True and 'False' as False in a boolean context
            # So, direct conversion using json.loads might work if values are proper JSON booleans.
            # Otherwise, string comparison is safer.
            has_bike_parking = attributes['BikeParking'].lower() == 'true'
        except AttributeError:
            # Handle cases where BikeParking might not be a string (e.g., actual boolean, though unlikely from MongoDB)
            has_bike_parking = bool(attributes['BikeParking'])

    has_business_parking = False
    if 'BusinessParking' in attributes:
        try:
            # BusinessParking is a string representation of a dictionary
            parking_dict = json.loads(attributes['BusinessParking'].replace('\'', '\"')) # replace single quotes with double quotes
            if any(parking_dict.values()):
                has_business_parking = True
        except (json.JSONDecodeError, AttributeError):
            # Handle cases where BusinessParking might be None or malformed
            pass

    if has_bike_parking or has_business_parking:
        qualified_businesses.add(business_id)

print("__RESULT__:")
print(json.dumps(len(qualified_businesses)))

